class Solution:
    def minimizeStringValue(self, s: str) -> str:
        count = [0] * 26
        questions = 0

        for c in s:
            if c == '?':
                questions += 1
            else:
                count[ord(c) - ord('a')] += 1

        replacements = []
        for _ in range(questions):
            min_char = count.index(min(count))
            replacements.append(chr(min_char + ord('a')))
            count[min_char] += 1

        replacements = sorted(replacements)
        result = []
        j = 0

        for c in s:
            if c == '?':
                result.append(replacements[j])
                j += 1
            else:
                result.append(c)

        return ''.join(result)

efficiency: HIGH
